-- ============================================================
-- A. COLLOCATIONS (20)
-- ============================================================

INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_family_B1_01', 'raise', 'children', 'raise children', '아이를 키우다', 'grow', '''grow''는 식물이나 머리카락에 쓰고, 사람을 양육할 때는 ''raise''를 써요.', 'They raised three children together.', '그들은 함께 세 아이를 키웠어요.', 'It''s not easy to raise children these days.', '요즘 아이를 키우는 건 쉽지 않아요.', 'B1', 'family', 1, 'parents children together'),
('col_family_B1_02', 'start', 'a family', 'start a family', '가정을 꾸리다', 'open', '''open a family''는 틀리고, 결혼해서 아이를 가지는 의미는 ''start a family''예요.', 'We''re planning to start a family next year.', '우리는 내년에 가정을 꾸릴 계획이에요.', 'They got married and started a family.', '그들은 결혼해서 가정을 꾸렸어요.', 'B1', 'family', 1, 'young couple baby'),
('col_family_B1_03', 'spend', 'time', 'spend time with family', '가족과 시간을 보내다', 'pass', '''pass time''은 시간을 때운다는 뉘앙스이고, 의미 있게 함께할 때는 ''spend time''을 써요.', 'I love to spend time with my family on weekends.', '저는 주말에 가족과 시간 보내는 걸 좋아해요.', 'He doesn''t spend enough time with his kids.', '그는 아이들과 충분한 시간을 보내지 않아요.', 'B1', 'family', 1, 'family dinner together'),
('col_family_B1_04', 'have', 'an argument', 'have an argument', '말다툼하다', 'do', '''do an argument''는 틀리고, 다툼·논쟁은 ''have an argument''로 표현해요.', 'My parents had an argument about money.', '부모님이 돈 문제로 말다툼했어요.', 'We had a big argument last night.', '우리는 어젯밤 크게 말다툼했어요.', 'B1', 'family', 1, 'siblings arguing'),
('col_family_B1_05', 'make', 'up', 'make up with someone', '누군가와 화해하다', 'fix', '''fix up''은 수리하다이고, 다툰 뒤 화해할 때는 ''make up''을 써요.', 'My sister and I always make up after a fight.', '언니와 저는 다투고 나면 항상 화해해요.', 'They made up after a long argument.', '그들은 오랜 다툼 끝에 화해했어요.', 'B1', 'family', 1, 'siblings hugging reconcile'),

('col_family_B2_01', 'honor', 'your parents', 'honor your parents', '부모를 공경하다', 'respect-only', '''respect''도 가능하지만, 깊은 존경과 효도의 뉘앙스는 ''honor''가 더 강해요.', 'In our culture, we honor our parents.', '우리 문화에서는 부모님을 공경해요.', 'She always tries to honor her parents'' wishes.', '그녀는 늘 부모님의 뜻을 공경하려 해요.', 'B2', 'family', 2, 'asian family respect bow'),
('col_family_B2_02', 'set', 'a good example', 'set a good example', '좋은 본보기가 되다', 'make', '''make an example''은 본보기로 벌준다는 뉘앙스이고, 모범을 보이는 건 ''set an example''이에요.', 'Older siblings should set a good example.', '손위 형제는 좋은 본보기가 되어야 해요.', 'Parents set a good example by reading every day.', '부모님은 매일 독서로 좋은 본보기가 되세요.', 'B2', 'family', 2, 'older sibling role model'),
('col_family_B2_03', 'establish', 'boundaries', 'establish boundaries', '경계를 정하다', 'build', '''build boundaries''보다 ''establish''가 더 자연스럽고, 인간관계의 선을 긋는 뉘앙스예요.', 'It''s important to establish boundaries with relatives.', '친척과 경계를 정하는 건 중요해요.', 'We established clear boundaries with our in-laws.', '우리는 시댁과 분명한 경계를 정했어요.', 'B2', 'family', 2, 'family conversation serious'),
('col_family_B2_04', 'resolve', 'conflicts', 'resolve conflicts', '갈등을 해결하다', 'solve', '''solve''도 가능하지만, 사람 사이의 갈등에는 ''resolve''가 더 격식 있고 자연스러워요.', 'Every family needs to learn how to resolve conflicts.', '모든 가족은 갈등 해결 방법을 배워야 해요.', 'They resolved their conflicts through honest talks.', '그들은 솔직한 대화로 갈등을 해결했어요.', 'B2', 'family', 2, 'family talking peace'),
('col_family_B2_05', 'maintain', 'ties', 'maintain family ties', '가족과의 유대를 유지하다', 'keep-only', '''keep ties''도 쓰지만, ''maintain''이 더 격식 있고 꾸준한 노력의 뉘앙스를 담아요.', 'It''s hard to maintain family ties when you live abroad.', '해외에 살면 가족 유대를 유지하기 어려워요.', 'We maintain ties through weekly video calls.', '우리는 매주 영상통화로 유대를 유지해요.', 'B2', 'family', 2, 'video call family'),

('col_family_C1_01', 'uphold', 'values', 'uphold family values', '가족의 가치를 지키다', 'hold', '''hold values''보다 ''uphold''는 ''굳건히 지키다''는 결의의 뉘앙스가 강해요.', 'They uphold traditional family values.', '그들은 전통적인 가족 가치를 지켜요.', 'She upholds the values her grandmother taught her.', '그녀는 할머니께서 가르치신 가치를 지켜요.', 'C1', 'family', 2, 'multigenerational family traditions'),
('col_family_C1_02', 'nurture', 'relationships', 'nurture relationships', '관계를 보살피며 키우다', 'grow', '''grow relationships''도 쓰이지만, ''nurture''는 ''정성껏 가꾸다''라는 따뜻한 결을 가져요.', 'You have to nurture relationships with your siblings.', '형제자매와의 관계를 정성껏 가꿔야 해요.', 'They nurtured their relationship over decades.', '그들은 수십 년에 걸쳐 관계를 가꿔 왔어요.', 'C1', 'family', 2, 'mother child garden'),
('col_family_C1_03', 'mediate', 'disputes', 'mediate disputes', '분쟁을 중재하다', 'middle', '''middle''은 동사로 잘 안 쓰고, 분쟁을 중재할 때는 ''mediate''가 정확한 단어예요.', 'The eldest son often mediates disputes at home.', '장남이 집안의 분쟁을 자주 중재해요.', 'She mediated the dispute between her brothers.', '그녀는 오빠들 사이의 분쟁을 중재했어요.', 'C1', 'family', 2, 'family mediation discussion'),
('col_family_C1_04', 'preserve', 'traditions', 'preserve family traditions', '가족 전통을 보존하다', 'save', '''save traditions''보다 ''preserve''가 ''소중히 보존하다''의 격식 있는 표현이에요.', 'They work hard to preserve their family traditions.', '그들은 가족 전통을 보존하려 노력해요.', 'My grandmother preserves recipes from her ancestors.', '할머니는 조상으로부터 내려온 요리법을 보존하세요.', 'C1', 'family', 2, 'traditional ceremony family'),
('col_family_C1_05', 'foster', 'independence', 'foster independence', '자립심을 길러주다', 'make', '''make independence''는 부자연스럽고, 자질을 길러줄 때는 ''foster''를 써요.', 'Good parents foster independence in their children.', '좋은 부모는 자녀의 자립심을 길러줘요.', 'She fostered independence by letting them choose.', '그녀는 선택권을 주며 자립심을 길러줬어요.', 'C1', 'family', 2, 'child confident solo'),

('col_family_C2_01', 'perpetuate', 'a legacy', 'perpetuate a family legacy', '가문의 유산을 영속시키다', 'continue', '''continue''보다 ''perpetuate''는 세대를 이어 ''영구히 잇다''는 무게 있는 표현이에요.', 'He vowed to perpetuate his family''s legacy.', '그는 가문의 유산을 영속시키겠다고 다짐했어요.', 'They perpetuate a legacy of public service.', '그들은 공직 봉사의 유산을 이어가요.', 'C2', 'family', 3, 'old family portrait estate'),
('col_family_C2_02', 'navigate', 'complexities', 'navigate family complexities', '복잡한 가족 관계를 헤쳐 나가다', 'pass', '''pass''는 단순히 지나가는 뉘앙스이고, ''navigate''는 신중히 풀어나간다는 의미예요.', 'Adults must navigate the complexities of blended families.', '어른은 복합 가족의 복잡함을 헤쳐 나가야 해요.', 'She navigates family complexities with grace.', '그녀는 가족의 복잡함을 우아하게 헤쳐 나가요.', 'C2', 'family', 3, 'complex family tree branches'),
('col_family_C2_03', 'reconcile', 'differences', 'reconcile differences', '차이를 화해시키다', 'fix', '''fix''는 가볍고, 깊은 갈등이나 신념 차이를 ''reconcile''로 풀어요.', 'They finally reconciled their differences after years.', '그들은 수년 만에 마침내 차이를 화해시켰어요.', 'It takes wisdom to reconcile generational differences.', '세대 차이를 화해시키려면 지혜가 필요해요.', 'C2', 'family', 3, 'two hands reconciliation'),
('col_family_C2_04', 'instill', 'principles', 'instill principles', '원칙을 심어주다', 'teach-only', '''teach''도 가능하지만, ''instill''은 가치관을 ''서서히 깊이 새기다''는 뉘앙스예요.', 'Parents instill principles in their children early on.', '부모는 아이에게 일찍부터 원칙을 심어줘요.', 'She instilled the principle of honesty in her sons.', '그녀는 아들들에게 정직의 원칙을 심어줬어요.', 'C2', 'family', 3, 'mother teaching child seriously'),
('col_family_C2_05', 'transcend', 'generations', 'transcend generations', '세대를 초월하다', 'cross', '''cross''는 단순히 건너가다이고, ''transcend''는 ''뛰어넘어 이어진다''는 깊은 의미예요.', 'Their love transcended generations.', '그들의 사랑은 세대를 초월했어요.', 'Some family stories transcend generations.', '어떤 가족 이야기는 세대를 초월해요.', 'C2', 'family', 3, 'old photo generations')
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- B. IDIOMS (20)
-- ============================================================

INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_family_B1_01', 'like father, like son', '부전자전', '아버지처럼, 아들도', '아버지와 아들이 성격이나 행동이 닮았을 때 써요. 칭찬·놀림 양쪽으로 다 쓸 수 있어요.', 'He plays football just like his dad — like father, like son.', '그는 아빠처럼 축구를 잘 해요 — 부전자전이에요.', 'Like father, like son, they both love books.', '부전자전, 둘 다 책을 좋아해요.', NULL, NULL, 'B1', 'family', 2, 'father son similar', 1),
('idm_family_B1_02', 'run in the family', '집안 내력이다', '가족 안에서 흐른다', '특정 성격·재능·질병이 가족 모두에게 있을 때 써요.', 'Musical talent runs in our family.', '음악 재능은 우리 집안 내력이에요.', 'Tall height runs in the family.', '키 큰 건 집안 내력이에요.', NULL, NULL, 'B1', 'family', 2, 'family generations trait', 2),
('idm_family_B1_03', 'blood is thicker than water', '피는 물보다 진하다', '피가 물보다 진하다', '가족 관계가 다른 어떤 관계보다 강하다는 의미예요. 한국 속담과 거의 같아요.', 'When trouble comes, blood is thicker than water.', '어려움이 닥치면 피는 물보다 진해요.', 'She helped her cousin — blood is thicker than water.', '그녀는 사촌을 도왔어요 — 피는 물보다 진하죠.', NULL, NULL, 'B1', 'family', 2, 'family hands together', 3),
('idm_family_B1_04', 'the apple doesn''t fall far from the tree', '그 부모에 그 자식', '사과는 나무에서 멀리 떨어지지 않는다', '자녀가 부모의 성격이나 행동을 닮았다는 표현이에요. 보통 가벼운 농담으로 써요.', 'He''s stubborn just like his mom — the apple doesn''t fall far from the tree.', '그는 엄마처럼 고집 세요 — 그 부모에 그 자식이죠.', 'The apple doesn''t fall far from the tree in their family.', '그 집은 그 부모에 그 자식이에요.', NULL, NULL, 'B1', 'family', 2, 'apple tree parent child', 4),
('idm_family_B1_05', 'the spitting image of', '~를 빼다 박은', '~의 침 뱉은 형상', '외모가 누군가와 매우 닮았을 때 써요. 보통 가족 간에 많이 써요.', 'She''s the spitting image of her grandmother.', '그녀는 할머니를 빼다 박았어요.', 'My son is the spitting image of me.', '제 아들은 저를 빼다 박았어요.', NULL, NULL, 'B1', 'family', 2, 'grandmother granddaughter resemblance', 5),

('idm_family_B2_01', 'tie the knot', '결혼하다', '매듭을 묶다', '''결혼하다''의 친근한 표현이에요. 격식 있는 자리보다 일상 대화에서 써요.', 'They''re finally tying the knot next month!', '그들이 드디어 다음 달 결혼해요!', 'When are you two going to tie the knot?', '두 분은 언제 결혼하실 거예요?', NULL, NULL, 'B2', 'family', 2, 'wedding hands knot', 1),
('idm_family_B2_02', 'settle down', '결혼해 정착하다', '내려앉다·자리잡다', '결혼해서 안정된 생활을 시작한다는 의미예요. ''calm down''(진정하다)과 헷갈리지 마세요.', 'He''s ready to settle down and start a family.', '그는 결혼해 정착하고 가정을 꾸릴 준비가 됐어요.', 'After years of travel, she finally settled down.', '오랜 여행 끝에 그녀는 마침내 정착했어요.', NULL, NULL, 'B2', 'family', 2, 'couple new home keys', 2),
('idm_family_B2_03', 'take after someone', '~를 닮다', '~의 뒤를 잇다', '외모·성격이 가족 구성원과 닮았을 때 써요. ''look like''보다 ''take after''가 더 자연스러워요.', 'You really take after your father.', '아버지를 정말 많이 닮았어요.', 'She takes after her mom in personality.', '그녀는 성격이 엄마를 닮았어요.', NULL, NULL, 'B2', 'family', 2, 'mother daughter similar smile', 3),
('idm_family_B2_04', 'the black sheep of the family', '집안의 골칫거리', '집안의 검은 양', '가족 중에서 다른 사람들과 다르거나 말썽을 부리는 사람을 가리켜요.', 'He''s always been the black sheep of the family.', '그는 늘 집안의 골칫거리였어요.', 'Every family has a black sheep.', '모든 가정에는 골칫거리 한 명쯤은 있죠.', NULL, NULL, 'B2', 'family', 2, 'black sheep flock', 4),
('idm_family_B2_05', 'bring up', '키우다·양육하다', '들어 올리다', '아이를 ''양육하다''의 의미이고, ''raise''와 거의 같은 뜻이에요.', 'She brought up three kids on her own.', '그녀는 혼자서 세 아이를 키웠어요.', 'I was brought up in a small village.', '저는 작은 마을에서 자랐어요.', NULL, NULL, 'B2', 'family', 2, 'parent lifting child', 5),

('idm_family_C1_01', 'a skeleton in the closet', '집안의 숨겨진 비밀', '벽장 속의 해골', '가족이 감추고 싶어 하는 부끄러운 비밀을 의미해요. 진지한 맥락에서 자주 써요.', 'Every family has a skeleton in the closet.', '모든 가족에게 숨겨진 비밀 하나쯤은 있어요.', 'He discovered a skeleton in his family''s closet.', '그는 집안의 숨겨진 비밀을 알게 됐어요.', NULL, NULL, 'C1', 'family', 2, 'closet door secret', 1),
('idm_family_C1_02', 'kissing cousins', '아주 가까운 친척', '입맞춤하는 사촌', '서로 입맞춤할 정도로 친한 사촌·친척을 뜻해요. 가까운 관계의 비유로도 써요.', 'They''re kissing cousins — always together.', '그들은 아주 가까운 사촌이에요 — 늘 붙어 다녀요.', 'Those two ideas are kissing cousins.', '그 두 아이디어는 매우 비슷해요.', NULL, NULL, 'C1', 'family', 2, 'cousins close hug', 2),
('idm_family_C1_03', 'born with a silver spoon in one''s mouth', '부유한 집안에서 태어나다', '입에 은수저를 물고 태어나다', '한국의 ''금수저''와 비슷한 표현이에요. 부유한 가정에서 태어났을 때 써요.', 'He was born with a silver spoon in his mouth.', '그는 부유한 집안에서 태어났어요.', 'Not everyone is born with a silver spoon in their mouth.', '누구나 부유하게 태어나는 건 아니에요.', NULL, NULL, 'C1', 'family', 2, 'silver spoon luxury', 3),
('idm_family_C1_04', 'in-laws and outlaws', '시댁·처가 식구들 (농담)', '시댁 식구와 무법자', '''in-laws''(시댁/처가)를 ''outlaws''(무법자)와 운으로 맞춘 농담이에요. 가볍게 써요.', 'The holidays mean in-laws and outlaws together.', '명절은 시댁 식구가 다 모이는 시간이죠.', 'I love my in-laws — and the outlaws too!', '저는 시댁 식구들 다 좋아해요!', NULL, NULL, 'C1', 'family', 2, 'extended family dinner', 4),
('idm_family_C1_05', 'the family tree', '가계도', '가족 나무', '가문의 조상부터 후손까지 이어지는 계보를 가리켜요.', 'She''s researching her family tree.', '그녀는 가계도를 조사하고 있어요.', 'Our family tree goes back 300 years.', '우리 가계도는 300년 전까지 거슬러 올라가요.', NULL, NULL, 'C1', 'family', 2, 'family tree chart roots', 5),

('idm_family_C2_01', 'a patriarchal legacy', '가부장적 유산', '가부장적 유산', '대대로 내려오는 남성 중심의 전통을 뜻해요. 학술적·비판적 맥락에서 자주 써요.', 'They struggle to break free from a patriarchal legacy.', '그들은 가부장적 유산에서 벗어나려 애써요.', 'The novel explores a patriarchal legacy.', '그 소설은 가부장적 유산을 다뤄요.', NULL, NULL, 'C2', 'family', 3, 'old patriarch portrait', 1),
('idm_family_C2_02', 'fly the nest', '독립해 집을 떠나다', '둥지를 떠나 날다', '성인이 된 자녀가 부모 집을 떠나 독립하는 것을 뜻해요. 시적 느낌이 있어요.', 'All her children have flown the nest.', '그녀의 자녀들은 모두 독립해 집을 떠났어요.', 'It''s hard when your kids fly the nest.', '아이들이 독립해 집을 떠날 때는 마음이 허전해요.', NULL, NULL, 'C2', 'family', 3, 'bird leaving nest', 2),
('idm_family_C2_03', 'cut from the same cloth', '같은 부류의 사람', '같은 천에서 잘라낸', '성격이나 가치관이 매우 비슷한 사람을 뜻해요. 가족·동료 모두에게 쓸 수 있어요.', 'The brothers are cut from the same cloth.', '그 형제들은 같은 부류의 사람이에요.', 'She and her mother are cut from the same cloth.', '그녀와 어머니는 정말 닮은 부류예요.', NULL, NULL, 'C2', 'family', 3, 'tailor cloth pattern', 3),
('idm_family_C2_04', 'across the generations', '세대를 넘어', '세대들에 걸쳐', '세대를 가로질러 이어지는 무엇을 표현할 때 써요. 격식 있고 문학적인 표현이에요.', 'Their wisdom has been passed down across the generations.', '그들의 지혜는 세대를 넘어 전해 내려왔어요.', 'Love endures across the generations.', '사랑은 세대를 넘어 이어져요.', NULL, NULL, 'C2', 'family', 3, 'generations hands old young', 4),
('idm_family_C2_05', 'the prodigal son', '돌아온 탕자', '방탕한 아들', '집을 떠났다가 돌아온 자식을 가리키는 성경 유래 표현이에요. 진중한 맥락에서 써요.', 'He returned home like the prodigal son.', '그는 돌아온 탕자처럼 집으로 돌아왔어요.', 'The prodigal son was welcomed with open arms.', '돌아온 탕자는 따뜻하게 맞아졌어요.', NULL, NULL, 'C2', 'family', 3, 'son returning home embrace', 5)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- C. NUANCES (6)
-- ============================================================

INSERT INTO nuances (id, word_a, word_b, word_c, ko_a, ko_b, ko_c, comparison, ex_a, ex_b, ex_c, ex4, ex4_ko, ex5, ex5_ko, tip, cefr, topic_id, priority, image_keyword) VALUES
('nuc_family_01', 'house', 'home', NULL, '집 (건물)', '집 (가정·보금자리)', NULL, '''house''는 물리적 건물을 뜻하고, ''home''은 가족과 함께하는 따뜻한 보금자리의 느낌을 담아요.', 'They bought a new house last year.', 'Home is where the family is.', NULL, NULL, NULL, NULL, NULL, '부동산·구조물은 ''house'', 정서적 보금자리는 ''home''으로 구분해서 써요.', 'B1', 'family', 2, 'house exterior cozy home interior'),
('nuc_family_02', 'family', 'relatives', NULL, '가족 (직계)', '친척 (확장된 가족)', NULL, '''family''는 보통 부모·자녀 등 가까운 직계, ''relatives''는 사촌·이모·삼촌 같은 확장된 친척이에요.', 'I live with my family.', 'My relatives came from all over for the holiday.', NULL, NULL, NULL, NULL, NULL, '같이 사는 직계는 ''family'', 명절에 모이는 확장 친척은 ''relatives''로 써요.', 'B1', 'family', 2, 'nuclear family extended family gathering'),
('nuc_family_03', 'marry', 'wed', NULL, '결혼하다 (일상)', '결혼하다 (격식·언론)', NULL, '''marry''는 일상 회화의 자연스러운 표현, ''wed''는 신문 기사나 격식 있는 발표에 더 자주 써요.', 'They will marry next spring.', 'The couple wed in a private ceremony.', NULL, NULL, NULL, NULL, NULL, '일상 대화는 ''marry'', 뉴스·헤드라인이나 시적인 표현은 ''wed''로 써요.', 'B2', 'family', 2, 'wedding ceremony bride groom'),
('nuc_family_04', 'raise', 'bring up', 'rear', '키우다 (미국식, 일반)', '키우다 (영국식, 일상)', '기르다 (격식·문어)', '''raise''는 미국식·중립, ''bring up''은 영국식·일상, ''rear''는 문어적·격식 있는 표현이에요.', 'She raised her kids alone.', 'I was brought up in Seoul.', 'The children were reared in the countryside.', NULL, NULL, NULL, NULL, '미국 영어는 ''raise'', 영국 영어 일상은 ''bring up'', 문어·격식은 ''rear''로 구분해요.', 'C1', 'family', 2, 'parent raising child generations'),
('nuc_family_05', 'siblings', 'brothers and sisters', NULL, '형제자매 (격식)', '형제자매 (일상)', NULL, '''siblings''는 격식·서면, ''brothers and sisters''는 친근한 일상 표현이에요.', 'Do you have any siblings?', 'I have two brothers and a sister.', NULL, NULL, NULL, NULL, NULL, '서류·면접에서는 ''siblings'', 가족 얘기 나누는 일상에는 ''brothers and sisters''를 써요.', 'C1', 'family', 2, 'siblings group photo'),
('nuc_family_06', 'ancestor', 'forefather', 'predecessor', '조상 (혈통)', '선조 (역사·격식)', '전임자 (직위·역할)', '''ancestor''는 혈연 조상, ''forefather''는 민족·역사적 선조, ''predecessor''는 직위·자리를 물려준 사람이에요.', 'My ancestors came from Jeju Island.', 'Our forefathers founded this nation.', 'She replaced her predecessor as CEO.', NULL, NULL, NULL, NULL, '혈통은 ''ancestor'', 역사·민족은 ''forefather'', 직책·직업은 ''predecessor''로 정확히 구분해요.', 'C2', 'family', 3, 'old portrait lineage history')
ON CONFLICT (id) DO NOTHING;
